INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '9a47611a-571b-4946-ae77-dbea56a3c57a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Grafana Alloy + OpenTelemetry — Wiring the LGTM Collector Pipeline$escape$,
  $escape$OpenTelemetry's SDK-to-collector model maps directly onto Grafana's LGTM stack: traces → Tempo, metrics → Mimir, logs → Loki — all funneled through Grafana Alloy. Alloy replaces the standalone OTel Collector with a River-config pipeline of typed, explicitly wired components.

Point your SDK's OTLP HTTP exporter at Alloy's receiver on port 4318. Inside Alloy, `otelcol.receiver.otlp` ingests the signal, `otelcol.processor.batch` buffers for throughput, and outputs fan out: `otelcol.exporter.otlp` forwards traces to Tempo's gRPC endpoint (`tempo:4317`), while `otelcol.exporter.prometheus` exposes metrics for Mimir scraping. River wires these as a typed graph — `output { traces = [otelcol.processor.batch.default.input] }` — and Alloy validates the entire pipeline at startup, rejecting misconfigured exporters before a single span arrives.

Once traces land in Tempo, switch to **Grafana Explore → TraceQL**: `{ .service.name = "api" && duration > 500ms }` surfaces slow spans instantly. Enable Tempo's derived fields to auto-link trace IDs to Loki log lines — no manual correlation needed. The entire signal path stays vendor-neutral at the SDK layer; only Alloy's exporter config is Grafana-specific.$escape$,
  $escape$ctx := context.Background()
exp, _ := otlptracehttp.New(ctx,
	otlptracehttp.WithEndpoint("http://alloy:4318"),
	otlptracehttp.WithInsecure(),
)
tp := trace.NewTracerProvider(
	trace.WithBatcher(exp),
	trace.WithResource(resource.NewWithAttributes(
		semconv.SchemaURL,
		semconv.ServiceName("my-api"),
	)),
)
otel.SetTracerProvider(tp)
defer tp.Shutdown(ctx)$escape$,
  $escape$go$escape$,
