INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e17a5ecc-eb89-4e26-bcd8-44ef9c74091d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Grafana Faro — Sentry-Style Error Capture, Source Maps, and Session Replay Inside Your Grafana Stack$escape$,
  $escape$Grafana Faro is the native answer to Sentry inside the Grafana stack — capturing frontend errors, Web Vitals, custom traces, and session recordings without leaving your existing Loki/Tempo pipeline. Install `@grafana/faro-web-sdk` and `@grafana/faro-web-tracing`, then call `initializeFaro()` once at app bootstrap.

`getWebInstrumentations()` automatically captures unhandled exceptions, console errors, and Core Web Vitals (LCP, FID, CLS), shipping them as structured Loki log streams tagged with `app`, `version`, and `session_id`. Add `TracingInstrumentation` and every `fetch`/`XHR` call emits an OpenTelemetry span to Tempo — distributed traces correlated to the exact frontend error that triggered them.

Source map support: upload `.map` files to Grafana Cloud's source map store (or self-hosted via the Faro collector's `sourceMaps.enabled: true` config), and stack traces in Grafana Explore de-obfuscate automatically.

Session replay uses `SessionInstrumentation` to record DOM events client-side. Replays surface in the Grafana Frontend Observability app, linked to the error event's `session_id` label in Loki — jumping from alert → trace → replay in one click without ever leaving your Grafana instance.$escape$,
  $escape$import { initializeFaro, getWebInstrumentations } from '@grafana/faro-web-sdk';
import { TracingInstrumentation } from '@grafana/faro-web-tracing';
import { SessionInstrumentation } from '@grafana/faro-web-sdk';

initializeFaro({
  url: 'https://<faro-collector-host>/collect',
  app: { name: 'my-app', version: '1.0.0', environment: 'production' },
  instrumentations: [
    ...getWebInstrumentations({ captureConsole: true }),
    new TracingInstrumentation(),
    new SessionInstrumentation(),
  ],
  batching: { enabled: true, sendTimeout: 500 },
});$escape$,
