INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2a476e1e-a34e-4957-8d2d-774e12a12102',
  '00000000-0000-0000-0000-000000000001',
  $escape$Grafana Loki — Structured Logs, Correlation IDs, and Retention That Actually Works$escape$,
  $escape$Grafana Loki ingests logs as streams identified by label sets — not indexed field values. This distinction is critical: labels like {app="api", env="prod"} determine cardinality and cost, while structured metadata lives inside the log line itself.

Use LogFmt or JSON log lines and parse them at query time with Loki's `| logfmt` or `| json` pipeline stages. For log levels, emit a `level` field in your structured payload — Loki's detected_fields will surface it automatically, and you can filter with `| level="error"`.

Correlation IDs are the real power move: inject a `trace_id` field into every log line, then link Loki datasource to Tempo in Grafana's datasource settings. Any log with a `traceID` field becomes a clickable link straight into the distributed trace — zero extra tooling.

For retention, configure per-stream policies in `loki.yaml` under `compactor.retention_enabled: true` with `stream_retention` rules. Pin high-value streams (errors, audit) to 90 days; debug streams to 7. This beats global TTLs by orders of magnitude for cost control.$escape$,
  $escape$# loki.yaml — per-stream retention + structured log pipeline
compactor:
  retention_enabled: true

limits_config:
  retention_period: 30d
  stream_retention:
    - selector: '{level="error"}'
      period: 90d
    - selector: '{level="debug"}'
      period: 7d

# LogQL: filter by level, extract trace_id, jump to Tempo
{
  app="api",
  env="prod"
}
| json
| level="error"
| line_format "{{.trace_id}} {{.msg}}"$escape$,
  $escape$bash$escape$,
