INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0005e779-0980-40b7-8b98-c3875418f2f9',
  '00000000-0000-0000-0000-000000000001',
  $escape$Grafana Metrics Design — Naming, Cardinality, and Choosing the Right Type$escape$,
  $escape$Grafana's query performance lives or dies on instrumentation quality. Name metrics using `{namespace}_{subsystem}_{name}_{unit}` — `http_server_request_duration_seconds`, not `duration`. Grafana's Explore autocomplete and variable template dropdowns rely on consistent prefixes to surface the right series.

Cardinality kills dashboards quietly. Every unique label combination creates a separate time series in Prometheus; Grafana loads all of them at panel render time. Labels like `user_id`, `trace_id`, or `path` with raw URL values balloon your TSDB and freeze Explore. Stick to bounded-cardinality labels: `status_code`, `method`, `region`.

Type selection determines your PromQL strategy in Grafana:

- **Counter**: always wrap in `rate()` or `increase()` — raw counter values are meaningless in time-series panels. Use `increase()` in Stat panels for totals over the dashboard time range.
- **Gauge**: current state (memory, queue depth) — query directly or use `min_over_time` / `max_over_time`.
- **Histogram**: the only type enabling percentile panels. `histogram_quantile(0.99, rate(http_request_duration_seconds_bucket[5m]))` powers your p99 SLO panel. Bucket boundaries are fixed at instrument time — Grafana cannot adjust them retroactively.$escape$,
  $escape$var (
    httpDuration = prometheus.NewHistogramVec(
        prometheus.HistogramOpts{
            Name:    "http_server_request_duration_seconds",
            Help:    "HTTP request latency in seconds.",
            Buckets: []float64{0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1, 2.5},
        },
        []string{"method", "status_code", "handler"}, // bounded cardinality only
    )
    activeConns = prometheus.NewGauge(prometheus.GaugeOpts{
        Name: "http_server_active_connections",
        Help: "Current number of active HTTP connections.",
    })
    requestsTotal = prometheus.NewCounterVec(
        prometheus.CounterOpts{Name: "http_server_requests_total"},
        []string{"method", "status_code"},
    )
)$escape$,
  $escape$go$escape$,
