INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8b85cded-fb93-46c4-99e0-51f9bd73314b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Grafana — High Cardinality Metrics Will Burn Your Budget (And How to Stop Them)$escape$,
  $escape$Every unique label-value combination in Prometheus/Mimir creates a distinct time series in TSDB. Add a `user_id` label to a request counter and you've multiplied your series count by your entire user base — Grafana Mimir starts rejecting writes once you breach `max_global_series_per_user` (default: 150k per tenant).

The cost is concrete: Grafana Cloud bills per active series, and TSDB head compaction degrades linearly with cardinality. Audit your exposure in Grafana Explore with `grafana_tsdb_head_series` or use Mimir's `/api/v1/cardinality/label_names` endpoint to identify the worst offenders.

Fix it at ingestion, not in dashboards. Grafana Alloy's `prometheus.relabel` component lets you strip or truncate unbounded labels before they hit remote_write. For traces, Grafana Tempo's tail-based sampler is the right lever: configure `tail_sampling` policies to keep 100% of error/slow spans while dropping 90%+ of healthy ones — far more cost-efficient than flat-rate head sampling at 10%. Instrument broadly; filter aggressively at the collector edge.$escape$,
  $escape$// Grafana Alloy — strip high-cardinality labels before Mimir ingestion
prometheus.relabel "cardinality_guard" {
  // Drop unbounded labels; each unique value = a new TSDB series
  rule {
    action = "labeldrop"
    regex  = "user_id|request_id|session_id"
  }

  // Truncate pod names to an 8-char prefix to cap replica explosion
  rule {
    source_labels = ["pod"]
    target_label  = "pod"
    regex         = "([a-z0-9-]{1,8}).*"
    replacement   = "${1}"
  }

  forward_to = [prometheus.remote_write.mimir.receiver]
}$escape$,
  $escape$bash$escape$,
