INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'dad7ce7d-17dd-4d94-9abc-00f19bac478c',
  '00000000-0000-0000-0000-000000000001',
  $escape$Grafana Synthetic Monitoring — Uptime Checks, Multi-Step API Tests, and SLA Alerting$escape$,
  $escape$Grafana Synthetic Monitoring runs checks from global probes and exposes results as Prometheus metrics you can alert on directly. Basic HTTP checks hit an endpoint and track `probe_success` and `probe_duration_seconds`. For multi-step API flows — auth → fetch → assert — use Scripted checks backed by k6. These run your k6 script from selected probe locations on a configurable interval (minimum 10s). Results land in your Grafana Cloud metrics store under the `synthetic_monitoring` namespace. For SLA alerting, create a Grafana Alerting rule querying `avg_over_time(probe_success{job="my-api"}[30d]) < 0.999` to fire when 30-day availability drops below 99.9%. Pair this with a `probe_duration_seconds{quantile="0.95"}` rule to catch latency degradation before users feel it. Checks are managed via the Synthetic Monitoring API or Terraform (`grafana_synthetic_monitoring_check` resource), so probe config lives in version control alongside your dashboards-as-code.$escape$,
  $escape$import http from 'k6/http';
import { check, fail } from 'k6';

export default function () {
  // Step 1: authenticate
  const loginRes = http.post('https://api.example.com/auth/token', {
    client_id: 'monitor',
    client_secret: __ENV.CLIENT_SECRET,
  });
  if (!check(loginRes, { 'login 200': (r) => r.status === 200 })) {
    fail('auth failed');
  }

  const token = loginRes.json('access_token');

  // Step 2: call protected endpoint
  const res = http.get('https://api.example.com/v1/status', {
    headers: { Authorization: `Bearer ${token}` },
  });
  check(res, {
    'status 200': (r) => r.status === 200,
    'latency < 500ms': (r) => r.timings.duration < 500,
    'healthy field true': (r) => r.json('healthy') === true,
  });
}$escape$,
  $escape$javascript$escape$,
