INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '213bf484-a62f-46ec-a9ea-b5c9d07d6c08',
  '00000000-0000-0000-0000-000000000001',
  $escape$Grafana Pyroscope — Continuous Profiling and Flame Graph Diff in Production$escape$,
  $escape$Grafana Pyroscope gives you always-on continuous profiling without the overhead of one-shot tools. Pyroscope scrapes pprof-compatible endpoints every 15s by default, storing profiles as compressed call-tree blocks queryable via ProfileQL.

In Grafana Explore > Profiles, pick a service_name and profile_type (e.g. process_cpu:cpu:nanoseconds:cpu:nanoseconds). The native flame graph panel — GA since Grafana 9.5 — renders call stacks width-proportional to CPU time. Wider frame = hotter path. Click any frame to scope the view; right-click to copy the symbol for a targeted ProfileQL query.

For production hotspot hunting, use Comparison Mode: set the left window to your degraded time range and the right to a healthy baseline. Grafana renders a delta flame graph — red frames regressed, blue improved — so you see exactly which call paths changed, not just that something got slower.

Pin label selectors like {service_name="checkout-api", pod=~"checkout-.*"} to isolate pod-level variance in Kubernetes deployments. Profiles are also linkable from Grafana Tempo traces via trace-to-profiles correlation, giving you the full latency → trace → hotspot path in one click.$escape$,
  $escape$// grafana-alloy config.river — scrape CPU + memory profiles
pyroscope.scrape "app_scrape" {
  targets = [{
    "__address__" = "localhost:6060",
    "service_name" = "checkout-api",
  }]
  forward_to = [pyroscope.write.default.receiver]

  profiling_config {
    profile.process_cpu { enabled = true }
    profile.memory      { enabled = true }
    profile.goroutine   { enabled = true }
  }
}

pyroscope.write "default" {
  endpoint { url = "http://pyroscope:4040" }
}$escape$,
  $escape$bash$escape$,
